using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public float damageMultiplier = 1f;

    public bool IsAlive => currentHealth > 0;

    private void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public int CalculateDamage()
    {
        return Mathf.Max(1, Mathf.RoundToInt(baseDamage * damageMultiplier));
    }

    public void TakeDamage(int incomingDamage, int defense = 0)
    {
        int finalDamage = CalculateFinalDamage(incomingDamage, defense);
        currentHealth = Mathf.Max(0, currentHealth - finalDamage);
    }

    public void Heal(int amount)
    {
        currentHealth = Mathf.Clamp(currentHealth + Mathf.Max(0, amount), 0, maxHealth);
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool SpendCurrency(int amount)
    {
        if (amount < 0) return false;
        if (currency < amount) return false;

        currency -= amount;
        return true;
    }

    public int CalculateFinalDamage(int incomingDamage, int defense)
    {
        int reduced = Mathf.Max(0, incomingDamage - Mathf.Max(0, defense));
        return Mathf.Max(1, reduced);
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int contactDamage = 8;
    public int defense = 2;

    public void TakeHit(PlayerStats player)
    {
        if (player == null) return;
        int damage = player.CalculateDamage();
        int finalDamage = Mathf.Max(1, damage - Mathf.Max(0, defense));
        health = Mathf.Max(0, health - finalDamage);
    }

    public void AttackPlayer(PlayerStats player, int playerDefense = 0)
    {
        if (player == null) return;
        player.TakeDamage(contactDamage, playerDefense);
    }
}

public class ShopItem
{
    public string itemId;
    public string displayName;
    public int basePrice;
    public int level;
    public int maxLevel;
    public int damageBonus;
    public int healthBonus;

    public ShopItem(string itemId, string displayName, int basePrice, int maxLevel, int damageBonus, int healthBonus)
    {
        this.itemId = itemId;
        this.displayName = displayName;
        this.basePrice = basePrice;
        this.maxLevel = maxLevel;
        this.damageBonus = damageBonus;
        this.healthBonus = healthBonus;
        level = 0;
    }

    public int GetCurrentPrice()
    {
        return basePrice + (level * basePrice / 2);
    }

    public bool CanPurchase()
    {
        return level < maxLevel;
    }
}

public class ShopSystem : MonoBehaviour
{
    public PlayerStats playerStats;

    public ShopItem swordUpgrade = new ShopItem("sword_01", "Sword Upgrade", 100, 10, 5, 0);
    public ShopItem armorUpgrade = new ShopItem("armor_01", "Armor Upgrade", 120, 10, 0, 20);

    public bool PurchaseSwordUpgrade()
    {
        return PurchaseItem(swordUpgrade);
    }

    public bool PurchaseArmorUpgrade()
    {
        return PurchaseItem(armorUpgrade);
    }

    public bool PurchaseItem(ShopItem item)
    {
        if (playerStats == null || item == null) return false;
        if (!item.CanPurchase()) return false;

        int price = item.GetCurrentPrice();
        if (!playerStats.SpendCurrency(price)) return false;

        item.level++;
        ApplyItemEffects(item);
        return true;
    }

    private void ApplyItemEffects(ShopItem item)
    {
        playerStats.baseDamage += item.damageBonus;
        playerStats.maxHealth += item.healthBonus;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth + item.healthBonus, 0, playerStats.maxHealth);
    }
}

public class CoinPickup : MonoBehaviour
{
    public int value = 25;

    private void OnTriggerEnter(Collider other)
    {
        PlayerStats player = other.GetComponent<PlayerStats>();
        if (player == null) return;

        player.AddCurrency(value);
        Destroy(gameObject);
    }
}